/**
 * Generate tag test data based on pattern
 *
 * @param pattern - The test data pattern to generate
 * @param overrides - Optional field overrides
 * @returns Generated test data
 *
 * @example
 * ```typescript
 * // Generate complete test data
 * const data = generateTagTestData('complete');
 *
 * // Generate unique test data with overrides
 * const customData = generateTagTestData('unique', {
 *   is_active: false,
 * });
 * ```
 */
export function generateTagTestData(
  pattern: TestDataPattern = 'complete',
  overrides: Partial<TagCreateRequest> = {}
): TagCreateRequest {
  let baseData: TagCreateRequest;

  switch (pattern) {
    case 'minimal':
      baseData = { ...minimalTagFixture };
      break;

    case 'complete':
      baseData = { ...completeTagFixture };
      break;

    case 'invalid':
      // Return invalid data (caller should handle validation failure)
      baseData = { ...invalidTagFixture } as TagCreateRequest;
      break;

    case 'unique':
      // Generate fresh unique values for each call
      baseData = {
        ...uniqueTagFixture,
        name: `Test Tag ${generateUniqueId()}`,
      };
      break;

    default:
      baseData = { ...completeTagFixture };
  }

  return { ...baseData, ...overrides };
}

/**
 * Generate multiple tag fixtures
 *
 * @param count - Number of fixtures to generate
 * @param pattern - The test data pattern to use as base
 * @param modifier - Optional function to modify each fixture
 * @returns Array of generated test data
 *
 * @example
 * ```typescript
 * // Generate 5 unique fixtures
 * const fixtures = generateMultipleTagFixtures(5, 'unique');
 *
 * // Generate fixtures with sequential numbering
 * const numbered = generateMultipleTagFixtures(3, 'complete', (data, index) => ({
 *   ...data,
 *   name: `Tag #${index + 1}`,
 * }));
 * ```
 */
export function generateMultipleTagFixtures(
  count: number,
  pattern: TestDataPattern = 'unique',
  modifier?: (data: TagCreateRequest, index: number) => TagCreateRequest
): TagCreateRequest[] {
  const fixtures: TagCreateRequest[] = [];

  for (let i = 0; i < count; i++) {
    let fixture = generateTagTestData(pattern);

    if (modifier) {
      fixture = modifier(fixture, i);
    } else if (pattern === 'unique') {
      // Add index to ensure uniqueness even with same timestamp
      fixture.name = `Test Tag ${generateUniqueId()}-${i}`;
    }

    fixtures.push(fixture);
  }

  return fixtures;
}

